#!/usr/bin/env node
const config=require("./config"),fetch=require("node-fetch");async function checkOpenSeaEvents(){if(console.log("🔍 OpenSea Events Check Script"),console.log("=".repeat(50)),console.log("📋 1. Configuration Check:"),console.log("   OpenSea API Key: "+(config.opensea.apiKey?"✅ Set":"❌ Missing")),console.log(`   CSV File: ${config.csvFile}`),!config.opensea.apiKey)return void console.log("❌ OpenSea API key is missing!");console.log("\n👥 2. Reading Wallets:");const fs=require("fs");if(!fs.existsSync(config.csvFile))return void console.log(`❌ ${config.csvFile} not found!`);const wallets=fs.readFileSync(config.csvFile,"utf8").trim().split("\n").slice(1).map((line=>{const[address,name]=line.split(",");return{address:address,name:name}}));console.log(`✅ Found ${wallets.length} wallets`),console.log("\n🔗 3. Testing OpenSea API:");try{const response=await fetch("https://api.opensea.io/api/v2/collections?limit=1",{headers:{"X-API-KEY":config.opensea.apiKey,Accept:"application/json"}});response.ok?(console.log("✅ OpenSea API is accessible"),console.log(`   Status: ${response.status}`),console.log(`   Rate limit remaining: ${response.headers.get("x-ratelimit-remaining")||"Unknown"}`)):(console.log(`❌ OpenSea API error: ${response.status}`),console.log(`   Response: ${await response.text()}`))}catch(error){console.log("❌ OpenSea API connection failed:",error.message)}console.log("\n📊 4. Checking Recent Events:");const walletsToCheck=wallets.slice(0,3);for(const wallet of walletsToCheck){console.log(`\n🔍 Checking ${wallet.name} (${wallet.address.substring(0,10)}...)`);try{const eventResponse=await fetch(`https://api.opensea.io/api/v2/events/accounts/${wallet.address}?event_type=sale&event_type=mint&limit=5`,{headers:{"X-API-KEY":config.opensea.apiKey,Accept:"application/json"}});if(eventResponse.ok){const events=(await eventResponse.json()).asset_events||[];console.log(`   ✅ Found ${events.length} recent events`),events.length>0&&events.slice(0,2).forEach(((event,index)=>{const timestamp=new Date(1e3*event.event_timestamp).toISOString(),type=event.event_type,nftName=event.nft?.name||"Unknown",collection=event.nft?.collection||"Unknown";console.log(`     Event ${index+1}: ${type} - ${nftName} (${collection})`),console.log(`       Time: ${timestamp}`),console.log(`       Transaction: ${event.transaction?.substring(0,20)}...`)}))}else console.log(`   ❌ Failed to fetch events: ${eventResponse.status}`);await new Promise((resolve=>setTimeout(resolve,1e3)))}catch(error){console.log(`   ❌ Error checking events: ${error.message}`)}}if(console.log("\n🤖 5. Bot Event Processing Check:"),fs.existsSync("bot.log")){const lines=fs.readFileSync("bot.log","utf8").split("\n"),openSeaLogs=lines.filter((line=>line.includes("OpenSea")||line.includes("Checking")||line.includes("Found")||line.includes("Processing")));openSeaLogs.length>0?(console.log("✅ Found OpenSea activity in bot logs:"),openSeaLogs.slice(-5).forEach((line=>{console.log(`   ${line.trim()}`)}))):console.log("❌ No OpenSea activity found in bot logs");const notificationLogs=lines.filter((line=>line.includes("Discord")||line.includes("notification")||line.includes("sent successfully")));notificationLogs.length>0?(console.log("\n📨 Found notification logs:"),notificationLogs.slice(-5).forEach((line=>{console.log(`   ${line.trim()}`)}))):console.log("\n❌ No notification logs found")}else console.log("❌ bot.log not found - bot might not be logging to file");console.log("\n"+"=".repeat(50)),console.log("🎯 OpenSea events check complete!"),console.log("\n💡 If no events are found:"),console.log("   - Check if wallets have recent activity"),console.log("   - Verify OpenSea API key is valid"),console.log("   - Check bot logs for errors"),console.log("   - Run: node simulate-nft-event.js to test notifications")}